import React, { useEffect, useContext, useState } from 'react';
import PerfectScrollbar from 'react-perfect-scrollbar';
import { useNavigate, Link } from 'react-router-dom';
import { AppSettings } from './../../config/app-settings.js';
import { Icon } from '@iconify/react';
import { useAuth } from '../../context/authContext.jsx';
import { getLayananAPI, getCapsterAPI } from '../../config/api';
import ProductItem from '../../components/pos/product-item.jsx';
import ProductModal from '../../components/pos/product-modal.jsx';
import { LineChart, Line, XAxis, YAxis, Tooltip, ResponsiveContainer } from 'recharts';

function PosCustomerOrder() {
  const { user, logout } = useAuth();
  const context = useContext(AppSettings);
  const [posMobileSidebarToggled, setPosMobileSidebarToggled] = useState(false);
  const [categoryType, setCategoryType] = useState('all');
  const [tableData, setTableData] = useState({ category: [], food: [] });
  const [orderData, setOrderData] = useState([]);
  const [modalData, setModalData] = useState(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalQuantity, setModalQuantity] = useState(1);
  const [modalSelectedAddon, setModalSelectedAddon] = useState([]);
  const [capsters, setCapsters] = useState([]);
  const [menuType, setMenuType] = useState('order'); // 'order', 'pengeluaran', 'dashboard'
  const [pengeluaranData, setPengeluaranData] = useState([]);
  const [pengeluaranForm, setPengeluaranForm] = useState({ desc: '', amount: '' });
  const navigate = useNavigate();
  const [loadingLayanan, setLoadingLayanan] = useState(false);

  const handleLogoutClick = (e) => {
    e.preventDefault();

    const confirmLogout = window.confirm("Yakin ingin logout?");
    if (confirmLogout) {
      logout();
      navigate("/");
    }
  }

  const handleLogout = (e) => {
    e.preventDefault();
    logout();
    navigate('/', { replace: true });
  };

  useEffect(() => {
    try {
      const savedCart = localStorage.getItem("pos_cart");
      if (savedCart) setOrderData(JSON.parse(savedCart));
    } catch {
      localStorage.removeItem("pos_cart");
    }
  }, []);

  useEffect(() => {
    localStorage.setItem("pos_cart", JSON.stringify(orderData));
  }, [orderData]);

  const toggleMobileSidebar = (e) => { e.preventDefault(); setPosMobileSidebarToggled(true); };
  const dismissMobileSidebar = (e) => { e.preventDefault(); setPosMobileSidebarToggled(false); };
  const showType = (e, type) => { e.preventDefault(); setCategoryType(type); };

  const filteredFood = tableData?.food?.filter(f => categoryType === 'all' || f.type === categoryType);
  const CategoryTabs = ({ className }) => (
    <div className={className}>
      <ul
        className="nav nav-tabs flex-nowrap overflow-auto px-2"
        style={{
          whiteSpace: 'nowrap',
          overflowX: 'auto',
          scrollbarWidth: 'none'
        }}
      >
        {tableData?.category?.map((cat, i) => (
          <li className="nav-item flex-shrink-0" key={i}>
            <a
              className={
                'nav-link' +
                (cat.type === categoryType ? ' active' : '')
              }
              onClick={(e) => showType(e, cat.type)}
              href="#/"
            >
              <i className={cat.icon}></i> {cat.text}
            </a>
          </li>
        ))}
      </ul>
    </div>
  );
  const handleItemClick = (food) => (e) => showPosItemModal(e, food);
  const showPosItemModal = (e, food) => { e.preventDefault(); if (!food.available) return; setModalData(food); setModalQuantity(1); setModalSelectedAddon([]); setIsModalOpen(true); };
  const getOrderTotal = () => orderData.length;
  const getSubTotalPrice = () => orderData.reduce((total, item) => total + Number(item.price) * Number(item.quantity), 0);

  const deductQty = (e, id) => { e.preventDefault(); setOrderData(prev => prev.map(item => item.id===id?{...item, quantity: Math.max(1,item.quantity-1)}:item)); };
  const addQty = (e, id) => { e.preventDefault(); setOrderData(prev => prev.map(item => item.id===id?{...item, quantity: item.quantity+1}:item)); };
  const addModalQty = (e) => { e.preventDefault(); setModalQuantity(q=>q+1); };
  const deductModalQty = (e) => { e.preventDefault(); setModalQuantity(q=>Math.max(1,q-1)); };

  useEffect(() => {
    async function fetchCapster() {
      const res = await getCapsterAPI(user?.cabangId);
      if (res.success) setCapsters(res.data);
    }
    if (user?.cabangId) fetchCapster();
  }, [user]);

  useEffect(() => {
    context.handleSetAppHeaderNone(true);
    context.handleSetAppSidebarNone(true);
    context.handleSetAppContentFullHeight(true);
    context.handleSetAppContentClass('p-0');

    const loadData = async () => {
      try {
        setLoadingLayanan(true);

        const result = await getLayananAPI(user?.cabangId);
        if (result.success) {
          setTableData(result);
        }

      } finally {
        setLoadingLayanan(false);
      }
    };
    loadData();

    return () => {
      context.handleSetAppHeaderNone(false);
      context.handleSetAppSidebarNone(false);
      context.handleSetAppContentFullHeight(false);
      context.handleSetAppContentClass('');
    };
  }, [user, context]);

  const handleGoToPayment = () => {
    setPosMobileSidebarToggled(false);
    navigate('/pos/customer-payment',{state:{orderData,total:Number(getSubTotalPrice())}});
  };

  const addItemToCart = ({modalData, selectedCapster, modalQuantity, selectedAddon=[]})=>{
    if(!modalData||!selectedCapster)return;
    const capster=capsters.find(c=>String(c.id)===String(selectedCapster));
    if(!capster)return;

    setOrderData(prev=>{
      const exist=prev.find(item=>item.layananId===modalData.id && item.capsterId===capster.id);
      if(exist) return prev.map(item=>item.id===exist.id?{...item,quantity:item.quantity+modalQuantity,selectedAddon}:item);
      return [...prev,{id:Date.now(),layananId:modalData.id,image:modalData.image,title:modalData.title,price:modalData.price,quantity:modalQuantity,capsterId:capster.id,capsterName:capster.nama,selectedAddon}];
    });
  };

  const handlePengeluaranSubmit=(e)=>{
    e.preventDefault();
    if(!pengeluaranForm.desc||!pengeluaranForm.amount)return;
    setPengeluaranData(prev=>[{id:Date.now(),desc:pengeluaranForm.desc,amount:parseFloat(pengeluaranForm.amount)},...prev]);
    setPengeluaranForm({desc:'',amount:''});
  };

  const dashboardData=[
    {day:'Sen',sales:500000},
    {day:'Sel',sales:750000},
    {day:'Rab',sales:600000},
    {day:'Kam',sales:900000},
    {day:'Jum',sales:800000},
    {day:'Sab',sales:1200000},
    {day:'Min',sales:700000},
  ];

  return (
    <>
      <div className={'pos pos-with-menu pos-with-sidebar '+(posMobileSidebarToggled?'pos-sidebar-mobile-toggled':'')} id="pos">

        {/* Sidebar Kiri: Menu Utama */}
        <div className="pos-menu">
          <div className="logo">
            <Link to="/"><div className="logo-img"><i className="fa fa-cut"></i></div><div className="logo-text">Kedai Tjoekoer MANA</div></Link>
          </div>
          <div className="nav-container">
            <PerfectScrollbar className="h-100">
              <ul className="nav nav-tabs mb-2 flex-nowrap">
                {['dashboard','order','pengeluaran'].map((tab,i)=>(
                  <li className="nav-item" key={i}>
                    <a 
                      className={'nav-link'+(menuType===tab?' active':'')} 
                      onClick={(e)=>{e.preventDefault();setMenuType(tab);}} 
                      href="#/"
                    >
                      {tab==='order'
                        ? 'Kasir'
                        : tab==='pengeluaran'
                        ? 'Pengeluaran'
                        : 'Dashboard'}
                    </a>
                  </li>
                ))}

                {/* Logout Tab */}
                <li className="nav-item">
                  <a
                    href="#/"
                    className="nav-link logout-link text-center"
                    onClick={handleLogoutClick}
                  >
                    <Icon icon="heroicons-outline:logout" className="me-2" />
                    Logout
                  </a>
                </li>
              </ul>
            </PerfectScrollbar>
          </div>
        </div>

        {/* Konten */}
        <div className="pos-content">
          <div className="pos-content-container h-100">
            <PerfectScrollbar className="h-100 p-3">
                            
              {menuType === 'order' && (
                <>
                  <CategoryTabs className="d-block d-lg-none mb-3" />
                  <CategoryTabs className="d-none d-lg-block mb-3 p-2 bg-light border-bottom" />
                </>
              )}

              {/* Grid layanan Pesanan */}
              {menuType === 'order' && (
                <>
                  {loadingLayanan ? (

                    // Loading Spinner
                    <div className="d-flex flex-column align-items-center justify-content-center py-5">
                      <div className="spinner-border text-theme mb-3" role="status" />
                      <div className="fw-semibold">Memuat layanan...</div>
                    </div>

                  ) : (

                    // Data tampil
                    <div className="product-row">
                      {filteredFood?.length > 0 ? (
                        filteredFood.map(food => (
                          <ProductItem
                            key={food.id}
                            food={food}
                            onClick={handleItemClick(food)}
                          />
                        ))
                      ) : (
                        <div className="text-center text-muted py-5">
                          Tidak ada layanan tersedia
                        </div>
                      )}
                    </div>

                  )}
                </>
              )}

              {/* Pengeluaran */}
              {menuType==='pengeluaran' && (
                <div className="p-3">
                  <h5>Pengeluaran</h5>
                  <form className="mb-3 d-flex gap-2" onSubmit={handlePengeluaranSubmit}>
                    <input type="text" className="form-control" placeholder="Deskripsi" value={pengeluaranForm.desc} onChange={e=>setPengeluaranForm({...pengeluaranForm,desc:e.target.value})}/>
                    <input type="number" className="form-control" placeholder="Jumlah (Rp)" value={pengeluaranForm.amount} onChange={e=>setPengeluaranForm({...pengeluaranForm,amount:e.target.value})}/>
                    <button className="btn btn-theme" type="submit">Tambah</button>
                  </form>
                  <table className="table table-striped table-bordered table-sm">
                    <thead><tr><th>Deskripsi</th><th>Jumlah</th></tr></thead>
                    <tbody>
                      {pengeluaranData.length>0?pengeluaranData.map(p=><tr key={p.id}><td>{p.desc}</td><td>Rp {p.amount.toLocaleString('id-ID')}</td></tr>):<tr><td colSpan={2} className="text-center text-muted">Belum ada pengeluaran</td></tr>}
                    </tbody>
                  </table>
                </div>
              )}

              {/* Dashboard */}
              {menuType==='dashboard' && (
                <div className="p-3">
                  <h5>Dashboard Penjualan</h5>
                  <ResponsiveContainer width="100%" height={300}>
                    <LineChart data={dashboardData} margin={{ top: 20, right: 20, left: 0, bottom: 0 }}>
                      <XAxis dataKey="day"/>
                      <YAxis/>
                      <Tooltip formatter={(value)=>`Rp ${value.toLocaleString('id-ID')}`}/>
                      <Line type="monotone" dataKey="sales" stroke="#4e73df" strokeWidth={2}/>
                    </LineChart>
                  </ResponsiveContainer>
                </div>
              )}

            </PerfectScrollbar>
          </div>

          {/* Floating button mobile */}
          {menuType==='order' && (
            <div className="d-block d-lg-none" style={{position:'fixed',bottom:20,right:20,zIndex:1020}}>
              <button className="btn btn-theme btn-lg rounded-pill shadow-lg" onClick={toggleMobileSidebar}>
                <Icon icon="heroicons-outline:shopping-cart" className="me-2"/>
                Order ({getOrderTotal()})
              </button>
            </div>
          )}
        </div>

        {/* Sidebar kanan */}
        {menuType==='order' && (
          <div className="pos-sidebar" id="pos-sidebar">
            <div className="pos-sidebar-header d-flex align-items-center justify-content-between px-3 py-2">

              {/* Judul */}
              <div className="fw-bold fs-5">
                Pesanan Baru
              </div>

              {/* Item Counter */}
              <div className="d-flex align-items-center">
                <span className="fw-semibold me-2 fs-6">
                  Item:
                </span>
                <span className="badge bg-theme fs-6 px-3 py-2">
                  {getOrderTotal()}
                </span>
              </div>

              {/* Close button mobile only */}
              <button
                onClick={dismissMobileSidebar}
                className="btn btn-theme rounded-circle d-lg-none d-flex align-items-center justify-content-center ms-2"
                style={{ width: '34px', height: '34px' }}
              >
                <Icon icon="heroicons-outline:x-mark" width="16" />
              </button>

            </div>
            <div className="pos-sidebar-body">
              <PerfectScrollbar className="h-100">
                {orderData.length>0?orderData.map(item=>(
                  <div className="pos-order" key={item.id}>
                    <div className="pos-order-product">
                      <div className="img" style={{backgroundImage:`url(${process.env.PUBLIC_URL}/${item.image})`}}></div>
                      <div className="flex-1">
                        <div className="h6 mb-1">{item.title}</div>
                        <div className="small text-muted">Capster: {item.capsterName}</div>
                        <div className="small text-muted">Rp {parseFloat(item.price).toLocaleString('id-ID')}</div>
                        <div className="d-flex mt-2 align-items-center">
                          <button onClick={(e)=>deductQty(e,item.id)} className="btn btn-secondary btn-xs">-</button>
                          <input type="text" className="form-control form-control-sm w-40px mx-2 text-center p-0" readOnly value={item.quantity}/>
                          <button onClick={(e)=>addQty(e,item.id)} className="btn btn-secondary btn-xs">+</button>
                        </div>
                      </div>
                    </div>
                    <div className="pos-order-price d-flex flex-column justify-content-between">
                      <div className="text-end fw-bold">Rp {(item.price*item.quantity).toLocaleString('id-ID')}</div>
                      <div className="text-end">
                        <button onClick={(e)=>setOrderData(prev=>prev.filter(o=>o.id!==item.id))} className="btn btn-default btn-xs text-danger border-0"><i className="fa fa-trash"></i></button>
                      </div>
                    </div>
                  </div>
                )):<div className="h-100 d-flex flex-column align-items-center justify-content-center text-muted"><Icon icon="heroicons-outline:shopping-bag" fontSize="48px" className="mb-2 opacity-2"/><div>Keranjang kosong</div></div>}
              </PerfectScrollbar>
            </div>

            <div className="pos-sidebar-footer">
              <hr/>
              <div className="d-flex align-items-center mb-3">
                <div className="h4 mb-0">Total Harga</div>
                <div className="flex-1 text-end h4 mb-0 text-theme">
                  Rp {getSubTotalPrice().toLocaleString('id-ID')}
                </div>
              </div>
              <div className="mt-3">
                <button className="btn btn-theme btn-lg w-100 rounded-3 fw-bold py-3" disabled={orderData.length===0} onClick={handleGoToPayment}>PROSES PEMBAYARAN</button>
              </div>
            </div>
          </div>
        )}

      </div>

      {/* Product Modal */}
      <ProductModal
        isOpen={isModalOpen}
        modalData={modalData}
        capsters={capsters}
        modalSelectedAddon={modalSelectedAddon}
        onAddonChange={(addonId,checked)=>setModalSelectedAddon(prev=>checked?[...prev,addonId]:prev.filter(a=>a!==addonId))}
        onAddToCart={({modalData,selectedCapster,modalQuantity,selectedAddon})=>{
          addItemToCart({modalData,selectedCapster,modalQuantity,selectedAddon});
          setModalQuantity(1); setModalData(null); setModalSelectedAddon([]); setIsModalOpen(false); setPosMobileSidebarToggled(true);
        }}
        onClose={()=>setIsModalOpen(false)}
      />

    </>
  );
}

export default PosCustomerOrder;