import React, { useState, useEffect } from "react";

const ProductItem = React.memo(({ food, onClick }) => {
  const [isMobile, setIsMobile] = useState(window.innerWidth < 992);

  useEffect(() => {
    const handleResize = () => setIsMobile(window.innerWidth < 992);
    window.addEventListener("resize", handleResize);
    return () => window.removeEventListener("resize", handleResize);
  }, []);

  return (
    <div className="product-container">
      <a
        href="#/"
        className={"product" + (!food.available ? " not-available" : "")}
        onClick={onClick}
      >
        <div
          className="img"
          style={{
            backgroundImage: `url(${process.env.PUBLIC_URL}/${food.image})`,
            minHeight: isMobile ? 120 : 180, // otomatis responsive
          }}
        ></div>
        <div className="text">
          <div className="title">{food.title}</div>
          <div className="desc">{food.description}</div>
          <div className="price">Rp {parseFloat(food.price).toLocaleString("id-ID")}</div>
        </div>
      </a>
    </div>
  );
});

export default ProductItem;