import React, { useState, useEffect } from 'react';

function ProductModal({ isOpen, modalData, capsters = [], modalSelectedAddon = [], onAddonChange, onAddToCart, onClose }) {
  const [selectedCapster, setSelectedCapster] = useState('');
  const [modalQuantity, setModalQuantity] = useState(1);

  // Reset state saat modal dibuka atau berubah
  useEffect(() => {
    if (isOpen) {
      setSelectedCapster('');
      setModalQuantity(1);
    }
  }, [isOpen, modalData]);

  if (!isOpen || !modalData) return null;

  const { image, title, description, price, addons = [] } = modalData;

  const addQty = () => setModalQuantity(q => q + 1);
  const deductQty = () => setModalQuantity(q => Math.max(1, q - 1));

  const handleAddToCart = () => {
    if (!selectedCapster) {
      alert('Pilih capster terlebih dahulu!');
      return;
    }
    onAddToCart({
      modalData,
      selectedCapster,
      modalQuantity,
      selectedAddon: modalSelectedAddon, // kirim addon terpilih
    });
    onClose();
  };

  return (
    <div className="modal modal-pos fade show" style={{ display: 'block' }}>
      <div className="modal-dialog modal-lg">
        <div className="modal-content">
          <div className="modal-body p-0">
            <button
              className="btn-close position-absolute top-0 end-0 m-3"
              onClick={onClose}
            />
            <div className="modal-pos-product">
              <div className="modal-pos-product-img">
                <div
                  className="img"
                  style={{
                    backgroundImage: `url(${process.env.PUBLIC_URL}/${image || 'placeholder.png'})`,
                  }}
                ></div>
              </div>
              <div className="modal-pos-product-info p-3">
                <h5 className="mb-2">{title || 'Nama Layanan'}</h5>
                <p className="text-muted mb-3">{description || ''}</p>
                <div className="mb-3 fw-bold">
                  Rp {parseFloat(price || 0).toLocaleString('id-ID')}
                </div>

                {/* Pilih Addon */}
                {addons.length > 0 && (
                  <div className="mb-3">
                    <label className="form-label fw-bold">Addon:</label>
                    {addons.map((addon) => (
                      <div key={addon.id} className="form-check">
                        <input
                          type="checkbox"
                          className="form-check-input"
                          value={addon.id}
                          checked={modalSelectedAddon.includes(addon.id)}
                          onChange={(e) => onAddonChange(addon.id, e.target.checked)}
                        />
                        <label className="form-check-label">{addon.name}</label>
                      </div>
                    ))}
                  </div>
                )}

                <div className="mb-3">
                  <label className="form-label fw-bold">Pilih Capster</label>
                  <select
                    className="form-select"
                    value={selectedCapster}
                    onChange={(e) => setSelectedCapster(e.target.value)}
                  >
                    <option value="">-- Pilih Capster --</option>
                    {capsters.map((c) => (
                      <option key={c.id} value={c.id}>
                        {c.nama}
                      </option>
                    ))}
                  </select>
                </div>

                <div className="d-flex align-items-center mb-3">
                  <div className="fw-bold me-3">Jumlah:</div>
                  <button className="btn btn-secondary" onClick={deductQty}>-</button>
                  <input
                    type="text"
                    className="form-control w-50px mx-2 text-center"
                    readOnly
                    value={modalQuantity}
                  />
                  <button className="btn btn-secondary" onClick={addQty}>+</button>
                </div>

                <button
                  className="btn btn-theme btn-lg w-100 rounded-pill"
                  onClick={handleAddToCart}
                  disabled={!selectedCapster}
                >
                  Tambah ke Keranjang
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default React.memo(ProductModal);