import React, { useState, useEffect, useContext, useMemo } from "react";
import { useLocation, useNavigate } from "react-router-dom";
import { AppSettings } from "../../config/app-settings.js";
import { saveTransactionPOS } from "../../config/api";
import { useAuth } from "../../context/authContext.jsx";
import { usePayment } from "../../hooks/usePayment";

function CustomerPayment() {
    const location = useLocation();
    const navigate = useNavigate();
    const context = useContext(AppSettings);
    const { user } = useAuth();
    const [loading, setLoading] = useState(false);

    useEffect(() => {
        const beforeUnload = (e) => {
            if (loading) {
                e.preventDefault();
                e.returnValue = "";
            }
        };
        window.addEventListener("beforeunload", beforeUnload);
        return () => window.removeEventListener("beforeunload", beforeUnload);
    }, [loading]);

    useEffect(() => {
        context.handleSetAppHeaderNone(true);
        context.handleSetAppSidebarNone(true);
        context.handleSetAppContentFullHeight(true);
        context.handleSetAppContentClass("p-0");

        return () => {
            context.handleSetAppHeaderNone(false);
            context.handleSetAppSidebarNone(false);
            context.handleSetAppContentFullHeight(false);
            context.handleSetAppContentClass("");
        };
    }, [context]);

    useEffect(() => {
        if (!location.state?.orderData?.length) {
            navigate("/pos/customer-order", { replace: true });
        }
    }, [location.state, navigate]);

    const orderData = location.state?.orderData ?? [];
    const totalAmount = Number(location.state?.total ?? 0);

    const {
        payments,
        totalPaid,
        remaining,
        change,
        canAddSplit,
        handleAddSplit,
        handleRemoveSplit,
        handleChange
    } = usePayment(totalAmount);

    const paymentMethods = useMemo(() => ["Tunai", "QRIS", "Transfer", "Debit"], []);

    const handleSubmit = async () => {
        if (loading) return;

        if (!user?.id || !user?.cabangId) {
            alert("User tidak valid");
            return;
        }

        if (!orderData.length) {
            alert("Tidak ada item dalam transaksi");
            return;
        }

        if (remaining > 0) {
            alert("Pembayaran kurang!");
            return;
        }

        if (payments.some(p => !p.method || Number(p.amount) <= 0)) {
            alert("Metode dan nominal harus diisi dengan benar!");
            return;
        }

        setLoading(true);
        try {
            const payload = {
                userId: user.id,
                cabangId: user.cabangId,
                items: orderData,
                payments: payments
            };

            const result = await saveTransactionPOS(payload);

            if (result.success) {
                localStorage.removeItem("pos_cart");
                alert("Pembayaran berhasil!\nInvoice: " + result.invoice);
                navigate("/pos/customer-order");
            } else {
                alert(result.message);
            }
        } catch (error) {
            console.error(error);
            alert("Terjadi kesalahan saat menyimpan transaksi");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="container-fluid py-4 position-relative">
            <div className="row">

                {/* LEFT SIDE - ORDER SUMMARY */}
                <div className="col-lg-6 mb-4">
                    <div className="card h-100 shadow-sm">
                        <div className="card-body">
                            <h4 className="mb-3">Ringkasan Pesanan</h4>
                            <div className="mb-3" style={{ maxHeight: "300px", overflowY: "auto" }}>
                                {orderData.map(item => (
                                    <div key={item.id} className="d-flex justify-content-between mb-2">
                                        <div>{item.title} x {item.quantity}</div>
                                        <strong>Rp {(item.price * item.quantity).toLocaleString("id-ID")}</strong>
                                    </div>
                                ))}
                            </div>
                            <hr />
                            <div className="d-flex justify-content-between">
                                <h5>Total</h5>
                                <h4 className="text-theme">Rp {totalAmount.toLocaleString("id-ID")}</h4>
                            </div>
                        </div>
                    </div>
                </div>

                {/* RIGHT SIDE - PAYMENT */}
                <div className="col-lg-6">
                    <div className="card shadow-sm mb-5">
                        <div className="card-body">
                            <h4 className="mb-3">Pembayaran</h4>

                            {payments.map((p, index) => (
                                <div key={index} className="border rounded p-3 mb-3">
                                    <div className="row">
                                        <div className="col-md-6 mb-2">
                                            <label className="form-label">Metode</label>
                                            <select
                                                className="form-select"
                                                value={p.method}
                                                onChange={e => handleChange(index, "method", e.target.value)}
                                            >
                                                <option value="">Pilih Metode</option>
                                                {paymentMethods.map((m, i) => (
                                                    <option key={i} value={m}>{m}</option>
                                                ))}
                                            </select>
                                        </div>
                                        <div className="col-md-6 mb-2">
                                            <label className="form-label">Nominal</label>
                                            <input
                                                type="number"
                                                className="form-control"
                                                value={p.amount}
                                                onChange={e => handleChange(index, "amount", e.target.value)}
                                            />
                                        </div>
                                    </div>
                                    <div className="mt-2 d-flex flex-wrap gap-2">
                                        {[10000, 20000, 50000, 100000].map((val, i) => (
                                            <button
                                                key={i}
                                                type="button"
                                                className="btn btn-outline-secondary btn-sm"
                                                onClick={() => handleChange(index, "amount", val)}
                                            >
                                                {val.toLocaleString("id-ID")}
                                            </button>
                                        ))}
                                        <button
                                            type="button"
                                            className="btn btn-outline-success btn-sm"
                                            onClick={() => handleChange(index, "amount", totalAmount)}
                                        >
                                            UANG PAS
                                        </button>
                                    </div>
                                    {payments.length > 1 && (
                                        <button
                                            className="btn btn-sm btn-danger mt-3"
                                            onClick={() => handleRemoveSplit(index)}
                                        >
                                            Hapus Split
                                        </button>
                                    )}
                                </div>
                            ))}

                            <button
                                className="btn btn-secondary mb-3"
                                onClick={handleAddSplit}
                                disabled={!canAddSplit}
                            >
                                + Tambah Split
                            </button>

                            <hr />

                            <div className="mb-2 d-flex justify-content-between">
                                <span>Total Dibayar</span>
                                <strong>Rp {totalPaid.toLocaleString("id-ID")}</strong>
                            </div>
                            <div className="mb-2 d-flex justify-content-between">
                                <span>Sisa</span>
                                <strong className={remaining > 0 ? "text-danger" : "text-success"}>
                                    Rp {remaining.toLocaleString("id-ID")}
                                </strong>
                            </div>
                            {change > 0 && (
                                <div className="mb-3 d-flex justify-content-between">
                                    <span>Kembalian</span>
                                    <strong className="text-success">
                                        Rp {change.toLocaleString("id-ID")}
                                    </strong>
                                </div>
                            )}

                            {/* DESKTOP BUTTONS */}
                            <div className="d-none d-lg-flex justify-content-between mt-4 gap-2">
                                <button
                                    className="btn btn-outline-secondary flex-fill fw-bold"
                                    onClick={() => navigate("/pos/customer-order")}
                                    disabled={loading}
                                >
                                    BATAL / KEMBALI
                                </button>
                                <button
                                    className="btn btn-theme flex-fill fw-bold"
                                    onClick={handleSubmit}
                                    disabled={remaining > 0 || loading || !payments.length}
                                >
                                    {loading ? "Memproses..." : "BAYAR SEKARANG"}
                                </button>
                            </div>

                        </div>
                    </div>
                </div>

            </div>

            {/* MOBILE FLOATING BUTTONS */}
            <div className="d-block d-lg-none position-fixed bottom-0 start-0 w-100 bg-white p-3 shadow border-top d-flex gap-2">
                <button
                    type="button"
                    className="btn btn-outline-secondary flex-fill fw-bold"
                    onClick={() => navigate("/pos/customer-order")}
                    disabled={loading}
                >
                    BATAL / KEMBALI
                </button>
                <button
                    type="button"
                    className="btn btn-theme flex-fill fw-bold"
                    disabled={remaining > 0 || loading || !payments.length}
                    onClick={handleSubmit}
                >
                    {loading ? "Memproses..." : "BAYAR SEKARANG"}
                </button>
            </div>
        </div>
    );
}

export default CustomerPayment;