import { useState, useMemo } from "react";

export function usePayment(totalAmount) {
  const [payments, setPayments] = useState([
    { method: "", amount: "" }
  ]);

  const totalPaid = useMemo(() => {
    return payments.reduce((sum, p) => {
      return sum + (Number(p.amount) || 0);
    }, 0);
  }, [payments]);

  const remaining = Math.max(0, totalAmount - totalPaid);
  const change = Math.max(0, totalPaid - totalAmount);
  const canAddSplit = remaining > 0;

  const handleAddSplit = () => {
    if (payments.some(p => !p.method || !p.amount)) {
      alert("Selesaikan split sebelumnya dulu");
      return;
    }
    setPayments(prev => [...prev, { method: "", amount: "" }]);
  };

  const handleRemoveSplit = (index) => {
    setPayments(prev => prev.filter((_, i) => i !== index));
  };

  const handleChange = (index, field, value) => {
    setPayments(prev =>
      prev.map((p, i) =>
        i === index ? { ...p, [field]: value } : p
      )
    );
  };

  return {
    payments,
    totalPaid,
    remaining,
    change,
    canAddSplit,
    handleAddSplit,
    handleRemoveSplit,
    handleChange
  };
}